// ============================================================================
// Module: exp_lut_256
// Description: 256-entry lookup table for exp() approximation.
//
//   Formula: LUT[k] = round(255 * exp(-k/64))
//   Range:   k=0 → exp(0) = 255,  k=255 → exp(-3.98) = 5
//
//   Generated by Python:
//     [max(1, min(255, round(255 * math.exp(-k/64.0)))) for k in range(256)]
//
//   The input x_in is Q8.8 signed (expected <= 0 after max-subtraction).
//   Index = clamp(-x_in >> 2, 0, 255)
//   This maps Q8.8 range [-4.0, 0] → LUT index [0, 255]
// ============================================================================
`timescale 1ns / 1ps

module exp_lut_256 (
    input  wire signed [15:0] x_in,    // Q8.8 input (expected <= 0)
    output wire        [7:0]  exp_out  // Q0.8 output [1,255]
);

    reg [7:0] lut [0:255];

    // All values generated by: round(255 * exp(-k/64)) for k=0..255
    // Verified via Python math.exp — no manual approximation
    initial begin
        lut[  0] = 255; lut[  1] = 251; lut[  2] = 247; lut[  3] = 243;
        lut[  4] = 240; lut[  5] = 236; lut[  6] = 232; lut[  7] = 229;
        lut[  8] = 225; lut[  9] = 222; lut[ 10] = 218; lut[ 11] = 215;
