        lut[ 32] = 155; lut[ 33] = 152; lut[ 34] = 150; lut[ 35] = 148;
        lut[ 36] = 145; lut[ 37] = 143; lut[ 38] = 141; lut[ 39] = 139;
        lut[ 40] = 136; lut[ 41] = 134; lut[ 42] = 132; lut[ 43] = 130;
        lut[ 44] = 128; lut[ 45] = 126; lut[ 46] = 124; lut[ 47] = 122;
        lut[ 48] = 120; lut[ 49] = 119; lut[ 50] = 117; lut[ 51] = 115;
        lut[ 52] = 113; lut[ 53] = 111; lut[ 54] = 110; lut[ 55] = 108;
        lut[ 56] = 106; lut[ 57] = 105; lut[ 58] = 103; lut[ 59] = 101;
        lut[ 60] = 100; lut[ 61] =  98; lut[ 62] =  97; lut[ 63] =  95;
        lut[ 64] =  94; lut[ 65] =  92; lut[ 66] =  91; lut[ 67] =  90;
