        lut[248] =   5; lut[249] =   5; lut[250] =   5; lut[251] =   5;
        lut[252] =   5; lut[253] =   5; lut[254] =   5; lut[255] =   5;
    end

    // Convert Q8.8 input to LUT index
    // x_in is <= 0 after max-subtraction
    // index = clamp(-x_in >> 2, 0, 255)
    wire signed [15:0] neg_x = -x_in;
    wire [15:0] shifted = neg_x >>> 2;
    wire [7:0]  idx = (shifted > 16'd255) ? 8'd255 :
                      (neg_x < 0) ? 8'd0 : shifted[7:0];

    assign exp_out = lut[idx];

endmodule
